mapper.select:
SELECT * FROM t_health_data
WHERE user_id = #{userId}
AND collected_at >= #{startTime}
AND collected_at <= #{endTime}
ORDER BY collected_at DESC

SELECT * FROM t_health_data
WHERE user_id = #{userId}
AND data_type = #{dataType}
AND collected_at >= #{startTime}
AND collected_at <= #{endTime}
ORDER BY collected_at DESC

SELECT * FROM t_health_data
WHERE user_id = #{userId}
AND data_type = #{dataType}
AND DATE(collected_at) = #{date}
ORDER BY collected_at DESC

SELECT * FROM t_health_data
WHERE user_id = #{userId}
AND collected_at = (
    SELECT MAX(collected_at) FROM t_health_data thd2
    WHERE thd2.user_id = #{userId}
    AND thd2.data_type = t_health_data.data_type
)

mapper.delete:
DELETE FROM t_health_data
WHERE user_id = #{userId}
AND collected_at < #{beforeDate}
